import React, { useState } from "react";
import { getWeatherPrediction } from "../api";
import { WiDaySunny, WiCloud, WiRain } from "react-icons/wi";
import "./WeatherDashboard.css";
import sunny from "../assets/sunny.png";
import rainy from "../assets/rainy.png";
import cloudy from "../assets/cloudy.png";

function WeatherDashboard() {

  const [city, setCity] = useState("");
  const [data, setData] = useState(null);
  let background = sunny;

  if (data) {

    if (data.prediction === "Sunny") background = sunny;
    else if (data.prediction === "Rainy") background = rainy;
    else background = cloudy;
    }
  const [loading, setLoading] = useState(false);

  const handleSearch = async () => {

    if (!city) return;

    setLoading(true);

    const result = await getWeatherPrediction(city);

    setData(result);
    setLoading(false);
  };

  const getIcon = () => {

    if (!data) return null;

    if (data.prediction === "Sunny")
      return <WiDaySunny className="weather-icon sun" />;

    if (data.prediction === "Rainy")
      return <WiRain className="weather-icon rain" />;

    return <WiCloud className="weather-icon cloud" />;
  };

  return (

    <div className="app">

      <h1 className="title">🌦 Weather AI Predictor</h1>

      <div className="search">

        <input
          type="text"
          placeholder="Enter city..."
          value={city}
          onChange={(e) => setCity(e.target.value)}
        />

        <button onClick={handleSearch}>
          Predict
        </button>

      </div>

      {loading && <div className="loader"></div>}

      {data && (

        <div className="card">

          {getIcon()}

          <h2>{data.city}</h2>

          <p>🌡 Temperature</p>
          <h3>{data.temperature}°C</h3>

          <p>💧 Humidity: {data.humidity}%</p>

          <h4>Prediction: {data.prediction}</h4>

        </div>

      )}

    </div>
  );
}

export default WeatherDashboard;
